#!/usr/bin/env python3
"""Parse CodeRabbit Change Impact blocks and walkthrough comments."""

from __future__ import annotations

import re
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class ChangeImpactLevel(str, Enum):
    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    UNKNOWN = "unknown"


NO_MANUAL_QA_PATTERNS = (
    r"no manual qa",
    r"minimal manual qa",
    r"tests sufficient",
    r"automated tests? (?:are |were )?sufficient",
    r"no manual qa required",
)


@dataclass
class CodeRabbitSignals:
    change_impact: ChangeImpactLevel = ChangeImpactLevel.UNKNOWN
    regression_risk: str = ""
    qa_recommendation: str = ""
    review_effort_score: Optional[int] = None
    review_effort_label: str = ""
    estimated_minutes: Optional[int] = None
    suggests_no_manual_qa: bool = False
    parsed_scenarios: list[dict] = field(default_factory=list)
    source: str = "none"

    def cis_score(self) -> int:
        base = {
            ChangeImpactLevel.LOW: 25,
            ChangeImpactLevel.MEDIUM: 55,
            ChangeImpactLevel.HIGH: 85,
            ChangeImpactLevel.UNKNOWN: 40,
        }[self.change_impact]
        if self.review_effort_score is not None:
            base = max(base, min(95, self.review_effort_score * 18))
        return base

    def should_skip(self, tpa_status: str = "") -> bool:
        if self.change_impact != ChangeImpactLevel.LOW:
            return False
        if not self.suggests_no_manual_qa:
            return False
        if tpa_status in ("failure", "error"):
            return False
        return True


def _impact_from_line(line: str) -> ChangeImpactLevel:
    lower = line.lower()
    if "high" in lower or "🔴" in line:
        return ChangeImpactLevel.HIGH
    if "medium" in lower or "🟡" in line:
        return ChangeImpactLevel.MEDIUM
    if "low" in lower or "🟢" in line:
        return ChangeImpactLevel.LOW
    return ChangeImpactLevel.UNKNOWN


def extract_change_impact_block(text: str) -> str:
    if not text:
        return ""
    block = text
    start_markers = (
        "<!-- This is an auto-generated comment: release notes by coderabbit.ai -->",
        "## Change Impact:",
    )
    for marker in start_markers:
        idx = block.find(marker)
        if idx >= 0:
            block = block[idx:]
            break
    if "## Change Impact:" not in block:
        idx = text.find("## Change Impact:")
        if idx >= 0:
            block = text[idx:]
        else:
            return ""
    end_markers = (
        "<!-- end of auto-generated comment: release notes by coderabbit.ai -->",
        "*Generated by CodeRabbitAI*",
    )
    for end in end_markers:
        idx = block.find(end)
        if idx >= 0:
            block = block[: idx + len(end)]
            break
    return block.strip()


def parse_change_impact_block(block: str) -> CodeRabbitSignals:
    signals = CodeRabbitSignals(source="coderabbit_body")
    if not block:
        return signals

    for line in block.splitlines():
        if "## Change Impact:" in line:
            signals.change_impact = _impact_from_line(line)

    risk_match = re.search(r"\*\*Regression Risk:\*\*\s*(.+?)(?=\n\*\*|\n\*Generated|\Z)", block, re.S | re.I)
    if risk_match:
        signals.regression_risk = " ".join(risk_match.group(1).split())

    qa_match = re.search(r"\*\*QA Recommendation:\*\*\s*(.+?)(?=\n\*Generated|\Z)", block, re.S | re.I)
    if qa_match:
        signals.qa_recommendation = " ".join(qa_match.group(1).split())
        lower = signals.qa_recommendation.lower()
        signals.suggests_no_manual_qa = any(re.search(p, lower) for p in NO_MANUAL_QA_PATTERNS)
        signals.parsed_scenarios = scenarios_from_recommendation(signals.qa_recommendation)

    return signals


def parse_walkthrough_comment(body: str) -> CodeRabbitSignals:
    extra = CodeRabbitSignals(source="coderabbit_walkthrough")
    if not body:
        return extra

    effort = re.search(
        r"🎯\s*(\d+)\s*\(([^)]+)\)\s*\|\s*⏱️\s*~(\d+)\s*minutes?",
        body,
    )
    if effort:
        extra.review_effort_score = int(effort.group(1))
        extra.review_effort_label = effort.group(2).strip()
        extra.estimated_minutes = int(effort.group(3))
    return extra


def scenarios_from_recommendation(qa_text: str) -> list[dict]:
    if not qa_text or any(re.search(p, qa_text.lower()) for p in NO_MANUAL_QA_PATTERNS):
        return []

    scenarios: list[dict] = []
    for part in re.split(r"[;,]|\band\b", qa_text):
        chunk = part.strip(" ,.")
        chunk = re.sub(
            r"^(?:Run targeted manual smoke tests for:|Manual QA should verify|Spot-check that|Verify that)\s*",
            "",
            chunk,
            flags=re.I,
        )
        if len(chunk) >= 12:
            scenarios.append({
                "title": chunk[:200],
                "source": "coderabbit_qa_recommendation",
            })
    if not scenarios and len(qa_text) > 20:
        scenarios.append({"title": qa_text[:200], "source": "coderabbit_qa_recommendation"})
    return scenarios[:10]


def merge_signals(body: str, walkthrough: str = "") -> CodeRabbitSignals:
    block = extract_change_impact_block(body)
    primary = parse_change_impact_block(block)
    if walkthrough:
        secondary = parse_walkthrough_comment(walkthrough)
        if primary.change_impact == ChangeImpactLevel.UNKNOWN and secondary.review_effort_score:
            if secondary.review_effort_score >= 4:
                primary.change_impact = ChangeImpactLevel.HIGH
            elif secondary.review_effort_score >= 3:
                primary.change_impact = ChangeImpactLevel.MEDIUM
            elif secondary.review_effort_score <= 2:
                primary.change_impact = ChangeImpactLevel.LOW
        if secondary.review_effort_score is not None:
            primary.review_effort_score = secondary.review_effort_score
            primary.review_effort_label = secondary.review_effort_label
            primary.estimated_minutes = secondary.estimated_minutes
    if primary.source == "none":
        primary.source = "fallback"
    return primary


def to_dict(signals: CodeRabbitSignals, pr_number: int) -> dict:
    return {
        "schema_version": "1.0",
        "source": signals.source,
        "pr_number": pr_number,
        "change_impact": signals.change_impact.value,
        "regression_risk": signals.regression_risk,
        "qa_recommendation_raw": signals.qa_recommendation,
        "parsed_scenarios": signals.parsed_scenarios,
        "review_effort_score": signals.review_effort_score,
        "review_effort_label": signals.review_effort_label,
        "estimated_minutes": signals.estimated_minutes,
        "suggests_no_manual_qa": signals.suggests_no_manual_qa,
        "cis_score": signals.cis_score(),
    }
